import{_ as a,o as r,c as t,ag as o}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"bamdra-memory-vector","description":"Product introduction for bamdra-memory-vector, the semantic recall plugin in the Bamdra OpenClaw suite.","frontmatter":{"title":"bamdra-memory-vector","description":"Product introduction for bamdra-memory-vector, the semantic recall plugin in the Bamdra OpenClaw suite."},"headers":[],"relativePath":"guide/memory-vector.md","filePath":"guide/memory-vector.md","lastUpdated":null}'),i={name:"guide/memory-vector.md"};function l(n,e,s,m,c,d){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="bamdra-memory-vector" tabindex="-1">bamdra-memory-vector <a class="header-anchor" href="#bamdra-memory-vector" aria-label="Permalink to &quot;bamdra-memory-vector&quot;">​</a></h1><p><code>bamdra-memory-vector</code> is the semantic recall plugin in the Bamdra OpenClaw suite, and it can also run independently.</p><h2 id="what-it-solves" tabindex="-1">What it solves <a class="header-anchor" href="#what-it-solves" aria-label="Permalink to &quot;What it solves&quot;">​</a></h2><p><code>bamdra-openclaw-memory</code> is strong at continuity. <code>bamdra-memory-vector</code> adds a lightweight semantic retrieval layer for cases where users return with fuzzy phrasing, incomplete keywords, or long gaps between related conversations.</p><h2 id="core-capabilities" tabindex="-1">Core capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to &quot;Core capabilities&quot;">​</a></h2><ul><li>Markdown-readable memory artifacts</li><li>local semantic index</li><li>user-scoped retrieval boundaries</li><li>top-k semantic recall for long-memory prompts</li></ul><h2 id="why-it-matters" tabindex="-1">Why it matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why it matters&quot;">​</a></h2><p>Many teams want semantic retrieval without deploying a separate heavy vector database. This plugin keeps that enhancement local, readable, and easy to manage.</p><h2 id="how-it-works-with-other-plugins" tabindex="-1">How it works with other plugins <a class="header-anchor" href="#how-it-works-with-other-plugins" aria-label="Permalink to &quot;How it works with other plugins&quot;">​</a></h2><ul><li>works independently as a local retrieval helper</li><li>stays optional when paired with <code>bamdra-openclaw-memory</code></li><li>does not replace the continuity-first memory runtime</li></ul><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/bamdra/bamdra-memory-vector" target="_blank" rel="noreferrer">bamdra/bamdra-memory-vector</a></li><li>All repositories: <a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li></ul>',12)])])}const u=a(i,[["render",l]]);export{p as __pageData,u as default};
